import{_ as l,o as i,c as e,a9 as r}from"./chunks/framework.STMWz9Nm.js";const k=JSON.parse('{"title":"FlinkSQL与实时数仓","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/10-Flink学习/05-FlinkSQL与实时数仓.md","filePath":"语言/java/10-Flink学习/05-FlinkSQL与实时数仓.md","lastUpdated":1776149370000}'),n={name:"语言/java/10-Flink学习/05-FlinkSQL与实时数仓.md"};function t(h,a,_,o,d,s){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="flinksql与实时数仓" tabindex="-1">FlinkSQL与实时数仓 <a class="header-anchor" href="#flinksql与实时数仓" aria-label="Permalink to “FlinkSQL与实时数仓”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>Flink SQL 是基于 SQL 方式操作流数据和表数据的能力。<br> 它在实时数仓和数据开发场景中非常常见。</p><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>很多实时计算需求并不适合全部通过 DataStream 手写。<br> Flink SQL 能显著降低开发门槛，也让数据处理逻辑更容易表达和维护。</p><h2 id="_3-核心内容" tabindex="-1">3. 核心内容 <a class="header-anchor" href="#_3-核心内容" aria-label="Permalink to “3. 核心内容”">​</a></h2><ul><li>动态表</li><li>流表关系认知</li><li>SQL 聚合与 Join</li><li>Catalog 与 Connector 基础认知</li><li>实时数仓分层思路</li></ul><h2 id="_4-学习重点" tabindex="-1">4. 学习重点 <a class="header-anchor" href="#_4-学习重点" aria-label="Permalink to “4. 学习重点”">​</a></h2><ul><li>理解 Flink SQL 不是简单“把批处理 SQL 搬过来”</li><li>理解动态表是流式 SQL 的核心抽象</li><li>理解实时数仓更关注链路和语义而不是单条 SQL</li></ul><h2 id="_5-常见问题" tabindex="-1">5. 常见问题 <a class="header-anchor" href="#_5-常见问题" aria-label="Permalink to “5. 常见问题”">​</a></h2><ul><li>用离线数仓思维直接套实时场景</li><li>忽视流式 Join 和迟到数据的复杂度</li><li>只会写 SQL，不理解底层运行代价</li></ul><h2 id="_6-练习建议" tabindex="-1">6. 练习建议 <a class="header-anchor" href="#_6-练习建议" aria-label="Permalink to “6. 练习建议”">​</a></h2><ul><li>写一个简单的实时聚合 SQL</li><li>总结动态表与普通关系表的差异</li><li>画一张实时数仓基础分层示意图</li></ul><h2 id="_7-自测问题" tabindex="-1">7. 自测问题 <a class="header-anchor" href="#_7-自测问题" aria-label="Permalink to “7. 自测问题”">​</a></h2><ul><li>Flink SQL 为什么适合实时数仓场景</li><li>动态表是什么</li><li>为什么流式 SQL 设计不能完全照搬离线思路</li></ul>',15)])])}const S=l(n,[["render",t]]);export{k as __pageData,S as default};
